import { ref, onMounted } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'
import store from '@/store'

export function useProfileData() {
  const resumeData = ref({
    id: null,
    name: '',
    avatar: '',
    gender: '',
    birth_date: '',
    phone: '',
    email: '',
    location: '',
    personal_summary: '',
    created_at: '',
    updated_at: ''
  })

  // 添加调试日志
  console.log('useProfileData initialized:', resumeData.value)

  // 添加个人简介展开状态控制
  const bioExpanded = ref(false)
  const showBioExpandButton = ref(false)

  // 切换个人简介展开状态
  const toggleBioExpand = () => {
    bioExpanded.value = !bioExpanded.value
  }

  const loading = ref(false)
  const error = ref(null)

  const fetchInitialData = async () => {
    loading.value = true
    error.value = null
    try {
      const response = await profile.getBasicInfo()
      console.log('Profile API response:', response)

      if (response.data) {
        resumeData.value = {
          ...resumeData.value,
          ...response.data
        }
        console.log('Updated resumeData:', resumeData.value)
        // 检查个人简介长度，决定是否显示展开按钮
        showBioExpandButton.value = response.data.personal_summary?.length > 100
      } else {
        throw new Error('获取资料失败：无数据返回')
      }
    } catch (err) {
      console.error('获取用户资料失败:', err)
      error.value = err.message || '获取用户资料失败'
      showToast(error.value, 'error')
    } finally {
      loading.value = false
    }
  }

  const updateResumeData = async (data) => {
    loading.value = true
    error.value = null
    try {
      const response = await profile.updateBasicInfo(data)
      console.log('Update response:', response)

      if (response?.data) {
        resumeData.value = {
          ...resumeData.value,
          ...response.data
        }
        // 更新后重新检查个人简介长度
        showBioExpandButton.value = response.data.personal_summary?.length > 100
        showToast('更新成功', 'success')
        return true
      }

      throw new Error(response?.message || '更新失败，请稍后重试')
    } catch (err) {
      console.error('更新用户资料失败:', err)
      error.value = err.message || '更新用户资料失败'
      showToast(error.value, 'error')
      return false
    } finally {
      loading.value = false
    }
  }

  // 获取处理后的个人简介文本
  const getBioText = () => {
    const text = resumeData.value.personal_summary
    if (!text) return ''
    if (!bioExpanded.value && text.length > 100) {
      return text.slice(0, 100) + '...'
    }
    return text
  }

  onMounted(() => {
    fetchInitialData()
  })

  return {
    resumeData,
    loading,
    error,
    bioExpanded,
    showBioExpandButton,
    toggleBioExpand,
    getBioText,
    fetchInitialData,
    updateResumeData
  }
}
